    97  func (s *Service) CallResource(ctx context.Context, req *backend.CallResourceRequest, sender backend.CallResourceResponseSender) error {
    98          if req == nil {
    99                  return errNilRequest
   100          }
   101
   102          if sender == nil {
   103                  return errNilSender
   104          }
   105
   106          p, exists := s.plugin(ctx, req.PluginContext.PluginID, req.PluginContext.PluginVersion)
   107          if !exists {
   108                  return plugins.ErrPluginNotRegistered
   109          }
   110
   111          removeConnectionHeaders(req.Headers)
   112          removeHopByHopHeaders(req.Headers)
   113          removeNonAllowedHeaders(req.Headers)
   114
   115          processedStreams := 0
   116          wrappedSender := backend.CallResourceResponseSenderFunc(func(res *backend.CallResourceResponse) error {
   117                  // Expected that headers and status are only part of first stream
   118                  if processedStreams == 0 && res != nil {
   119                          if len(res.Headers) > 0 {
   120                                  removeConnectionHeaders(res.Headers)
   121                                  removeHopByHopHeaders(res.Headers)
   122                                  removeNonAllowedHeaders(res.Headers)
   123                          } else {
   124                                  res.Headers = map[string][]string{}
   125                          }
   126
   127                          proxyutil.SetProxyResponseHeaders(res.Headers)
   128                          ensureContentTypeHeader(res)
   129                  }
   130
   131                  processedStreams++
   132                  return sender.Send(res)
   133          })
   134
   135          err := p.CallResource(ctx, req, wrappedSender)
   136          if err != nil {
   137                  if errors.Is(err, context.Canceled) {
   138                          return plugins.ErrPluginRequestCanceledErrorBase.Errorf("client: call resource request canceled: %w", err)
   139                  }
   140
   141                  return plugins.ErrPluginRequestFailureErrorBase.Errorf("client: failed to call resources: %w", err)
   142          }
   143
   144          return nil
   145  }
