   356  func logEmptyRefids(queries []v0alpha1.DataQuery, logger log.Logger) {
   357          emptyCount := 0
   358
   359          for _, q := range queries {
   360                  if q.RefID == "" {
   361                          emptyCount += 1
   362                  }
