   132  func (q *connectionsProvider) asConnection(ds *datasources.DataSource, ns string) (v *queryV0.DataSourceConnection, err error) {
   133          gv, err := q.registry.GetDatasourceGroupVersion(ds.Type)
   134          if err != nil {
   135                  return nil, fmt.Errorf("datasource type %q does not map to an apiserver %w", ds.Type, err)
   136          }
   137
   138          v = &queryV0.DataSourceConnection{
   139                  ObjectMeta: metav1.ObjectMeta{
   140                          Name:              queryV0.DataSourceConnectionName(gv.Group, ds.UID),
   141                          Namespace:         ns,
   142                          CreationTimestamp: metav1.NewTime(ds.Created),
   143                          ResourceVersion:   fmt.Sprintf("%d", ds.Updated.UnixMilli()),
   144                          Generation:        int64(ds.Version),
   145                  },
   146                  Title: ds.Name,
   147                  Datasource: queryV0.DataSourceConnectionRef{
   148                          Group:   gv.Group,
   149                          Version: gv.Version,
   150                          Name:    ds.UID,
   151                  },
   152          }
   153          v.UID = gapiutil.CalculateClusterWideUID(v) // UID is unique across all groups
   154          if !ds.Updated.IsZero() {
   155                  meta, err := utils.MetaAccessor(v)
   156                  if err != nil {
   157                          meta.SetUpdatedTimestamp(&ds.Updated)
   158                  }
   159          }
   160          return v, err
   161  }

