   169          if d.plugins == nil {
   170                  err := d.updatePlugins()
   171                  if err != nil {
   172                          return schema.GroupVersion{}, err
   173                  }
   174          }
   175
   176          var err error
   177          gv, ok := d.apis[pluginId]
   178          if !ok {
   179                  err = fmt.Errorf("no API found for id: %s", pluginId)
   180          }
   181          return gv, err
   182  }
   183
   184  // GetDatasourcePlugins no namespace? everything that is available
   185  func (d *pluginRegistry) GetDatasourceApiServers(ctx context.Context) (*query.DataSourceApiServerList, error) {
   186          d.pluginsMu.Lock()
   187          defer d.pluginsMu.Unlock()
   188
   189          if d.plugins == nil {
   190                  err := d.updatePlugins()
   191                  if err != nil {
   192                          return nil, err
   193                  }
   194          }
   195
   196          return d.plugins, nil
   197  }
   198
   199  // This should be called when plugins change
   200  func (d *pluginRegistry) updatePlugins() error {
   201          groupToPlugin := map[string]string{}
   202          apis := map[string]schema.GroupVersion{}
   203          result := &query.DataSourceApiServerList{
   204                  ListMeta: metav1.ListMeta{
   205                          ResourceVersion: fmt.Sprintf("%d", time.Now().UnixMilli()),
   206                  },
   207          }
   208
   209          // TODO? only backend plugins
   210          for _, dsp := range d.pluginStore.Plugins(context.Background(), plugins.TypeDataSource) {
   211                  ts := setting.BuildStamp * 1000
   212                  if dsp.Info.Build.Time > 0 {
   213                          ts = dsp.Info.Build.Time
   214                  }
   215
   216                  group, err := plugins.GetDatasourceGroupNameFromPluginID(dsp.ID)
   217                  if err != nil {
   218                          return err
   219                  }
   220                  gv := schema.GroupVersion{Group: group, Version: "v0alpha1"} // default version
   221                  apis[dsp.ID] = gv
   222                  for _, alias := range dsp.AliasIDs {
   223                          apis[alias] = gv
   224                  }
   225                  groupToPlugin[group] = dsp.ID
   226
   227                  ds := query.DataSourceApiServer{
   228                          ObjectMeta: metav1.ObjectMeta{
   229                                  Name:              dsp.ID,
   230                                  CreationTimestamp: metav1.NewTime(time.UnixMilli(ts)),
   231                          },
   232                          Title:        dsp.Name,
   233                          AliasIDs:     dsp.AliasIDs,
   234                          GroupVersion: gv.String(),
   235                          Description:  dsp.Info.Description,
   236                  }
   237                  result.Items = append(result.Items, ds)
   238          }
   239
   240          d.plugins = result
   241          d.apis = apis
   242          d.groupToPlugin = groupToPlugin
   243          return nil
   244  }
