   201                          return plugins.ErrMethodNotImplemented
   202                  }
   203
   204                  return fmt.Errorf("%v: %w", "Failed to call resource", err)
   205          }
   206
   207          for {
   208                  protoResp, err := protoStream.Recv()
   209                  if err != nil {
   210                          if status.Code(err) == codes.Unimplemented {
