   215                                  return nil
   216                          }
   217
   218                          return fmt.Errorf("%v: %w", "failed to receive call resource response", err)
   219                  }
   220
   221                  if err := sender.Send(backend.FromProto().CallResourceResponse(protoResp)); err != nil {
   222                          return err
   223                  }
   224          }
   225  }
