   146  }
   147
   148  func (p *grpcPlugin) getPluginClient(ctx context.Context) (*ClientV2, bool) {
   149          p.mutex.RLock()
   150          defer p.mutex.RUnlock()
   151          if p.client != nil && !p.client.Exited() && p.pluginClient != nil {
   152                  return p.pluginClient, true
   153          }
   154
   155          logger := p.Logger().FromContext(ctx)
   156          if p.state == pluginStateNotStarted {
   157                  logger.Debug("Plugin client has not been started yet")
   158          }
   159
   160          if p.state == pluginStateStartInit {
   161                  logger.Debug("Plugin client is starting")
   162          }
   163
   164          if p.state == pluginStateStartFail {
   165                  logger.Debug("Plugin client failed to start")
