    15  // Request is similar to plugins.DataQuery but with the Time Ranges is per Query.
    16  type Request struct {
    17          Headers map[string]string
    18          Debug   bool
    19          OrgId   int64
    20          Queries []Query
    21          User    identity.Requester
    22  }
    23
    24  // Query is like plugins.DataSubQuery, but with a a time range, and only the UID
    25  // for the data source. Also interval is a time.Duration.
    26  type Query struct {
    27          RefID         string
    28          TimeRange     TimeRange
    29          DataSource    *datasources.DataSource `json:"datasource"`
    30          JSON          json.RawMessage
    31          Interval      time.Duration
    32          QueryType     string
    33          MaxDataPoints int64
    34  }
    35
    36  // TimeRange is a time.Time based TimeRange.
    37  type TimeRange interface {
    38          AbsoluteTime(now time.Time) backend.TimeRange
    39  }
    40
    41  type AbsoluteTimeRange struct {
    42          From time.Time
    43          To   time.Time
    44  }
    45
    46  func (r AbsoluteTimeRange) AbsoluteTime(_ time.Time) backend.TimeRange {
    47          return backend.TimeRange{
    48                  From: r.From,
    49                  To:   r.To,
    50          }
    51  }
    52
    53  // RelativeTimeRange is a time range relative to some absolute time.
    54  type RelativeTimeRange struct {
    55          From time.Duration
    56          To   time.Duration
    57  }
    58
    59  func (r RelativeTimeRange) AbsoluteTime(t time.Time) backend.TimeRange {
    60          return backend.TimeRange{
    61                  From: t.Add(r.From),
    62                  To:   t.Add(r.To),
    63          }
    64  }
    65
    66  // TransformData takes Queries which are either expressions nodes
    67  // or are datasource requests.
    68  func (s *Service) TransformData(ctx context.Context, now time.Time, req *Request) (r *backend.QueryDataResponse, err error) {
    69          if s.isDisabled() {
    70                  return nil, fmt.Errorf("server side expressions are disabled")
    71          }
    72
    73          start := time.Now()
    74          ctx, span := s.tracer.Start(ctx, "SSE.TransformData")
    75          defer func() {
    76                  var respStatus string
    77                  switch err {
    78                  case nil:
    79                          respStatus = "success"
    80                  default:
    81                          respStatus = "failure"
    82                  }
    83                  duration := float64(time.Since(start).Nanoseconds()) / float64(time.Millisecond)
    84                  s.metrics.ExpressionsQuerySummary.WithLabelValues(respStatus).Observe(duration)
    85
    86                  span.End()
    87          }()
    88
    89          // Build the pipeline from the request, checking for ordering issues (e.g. loops)
    90          // and parsing graph nodes from the queries.
    91          pipeline, err := s.BuildPipeline(ctx, req)
    92          if err != nil {
    93                  return nil, err
    94          }
    95
    96          // Execute the pipeline
    97          responses, err := s.ExecutePipeline(ctx, now, pipeline)
    98          if err != nil {
    99                  return nil, err
   100          }
   101
   102          // Get which queries have the Hide property so they those queries' results
   103          // can be excluded from the response.
   104          hidden, err := hiddenRefIDs(req.Queries)
   105          if err != nil {
   106                  return nil, err
   107          }
   108
   109          if len(hidden) != 0 {
   110                  filteredRes := backend.NewQueryDataResponse()
   111                  for refID, res := range responses.Responses {
   112                          if _, ok := hidden[refID]; !ok {
   113                                  filteredRes.Responses[refID] = res
   114                          }
   115                  }
   116                  responses = filteredRes
   117          }
   118
   119          return responses, nil
   120  }
   121
   122  func hiddenRefIDs(queries []Query) (map[string]struct{}, error) {
   123          hidden := make(map[string]struct{})
   124
   125          for _, query := range queries {
   126                  hide := struct {
   127                          Hide bool `json:"hide"`
   128                  }{}
   129
   130                  if err := json.Unmarshal(query.JSON, &hide); err != nil {
   131                          return nil, err
   132                  }
   133
   134                  if hide.Hide {
   135                          hidden[query.RefID] = struct{}{}
   136                  }
   137          }
   138          return hidden, nil
   139  }

