    13          "github.com/grafana/grafana/pkg/infra/tracing"
    14          "github.com/grafana/grafana/pkg/services/datasources"
    15          "github.com/grafana/grafana/pkg/services/featuremgmt"
    16  )
    17
    18  type ResultConverter struct {
    19          Features featuremgmt.FeatureToggles
    20          Tracer   tracing.Tracer
    21  }
    22
    23  func (c *ResultConverter) Convert(ctx context.Context,
    24          datasourceType string,
    25          frames data.Frames,
    26  ) (string, mathexp.Results, error) {
    27          if len(frames) == 0 {
    28                  return "no-data", mathexp.Results{Values: mathexp.Values{mathexp.NewNoData()}}, nil
    29          }
    30
    31          var dt data.FrameType
    32          dt, useDataplane, _ := shouldUseDataplane(frames, logger, c.Features.IsEnabled(ctx, featuremgmt.FlagDisableSSEDataplane))
    33          if useDataplane {
    34                  logger.Debug("Handling SSE data source query through dataplane", "datatype", dt)
    35                  result, err := handleDataplaneFrames(ctx, c.Tracer, c.Features, dt, frames)
    36                  return fmt.Sprintf("dataplane-%s", dt), result, err
    37          }
    38
    39          if isAllFrameVectors(datasourceType, frames) { // Prometheus Specific Handling
    40                  vals, err := framesToNumbers(frames)
    41                  if err != nil {
    42                          return "", mathexp.Results{}, fmt.Errorf("failed to read frames as numbers: %w", err)
    43                  }
    44                  return "vector", mathexp.Results{Values: vals}, nil
    45          }
    46
    47          if len(frames) == 1 {
    48                  frame := frames[0]
    49                  // Handle Untyped NoData
    50                  if len(frame.Fields) == 0 {
    51                          return "no-data", mathexp.Results{Values: mathexp.Values{mathexp.NoData{Frame: frame}}}, nil
    52                  }
    53
    54                  // Handle Numeric Table
    55                  if frame.TimeSeriesSchema().Type == data.TimeSeriesTypeNot && isNumberTable(frame) {
    56                          numberSet, err := extractNumberSet(frame)
    57                          if err != nil {
    58                                  return "", mathexp.Results{}, err
    59                          }
    60                          vals := make([]mathexp.Value, 0, len(numberSet))
    61                          for _, n := range numberSet {
    62                                  vals = append(vals, n)
    63                          }
    64                          return "number set", mathexp.Results{
    65                                  Values: vals,
    66                          }, nil
    67                  }
    68          }
    69
    70          filtered := make([]*data.Frame, 0, len(frames))
    71          totalLen := 0
    72          for _, frame := range frames {
    73                  schema := frame.TimeSeriesSchema()
    74                  // Check for TimeSeriesTypeNot in InfluxDB queries. A data frame of this type will cause
    75                  // the WideToMany() function to error out, which results in unhealthy alerts.
    76                  // This check should be removed once inconsistencies in data source responses are solved.
    77                  if schema.Type == data.TimeSeriesTypeNot && datasourceType == datasources.DS_INFLUXDB {
    78                          logger.Warn("Ignoring InfluxDB data frame due to missing numeric fields")
    79                          continue
    80                  }

