    11          "github.com/grafana/grafana/pkg/services/datasources"
    12  )
    13
    14  type parsedQuery struct {
    15          datasource *datasources.DataSource
    16          query      backend.DataQuery
    17          rawQuery   *simplejson.Json
    18  }
    19
    20  type parsedRequest struct {
    21          hasExpression bool
    22          parsedQueries map[string][]parsedQuery
    23          dsTypes       map[string]bool
    24  }
    25
    26  func (pr parsedRequest) getFlattenedQueries() []parsedQuery {
    27          queries := make([]parsedQuery, 0)
    28          for _, pq := range pr.parsedQueries {
    29                  queries = append(queries, pq...)
    30          }
    31          return queries
    32  }
    33
    34  func (pr parsedRequest) validateRequest(ctx context.Context) error {
    35          refIds := make(map[string]bool)
    36          for _, pq := range pr.parsedQueries {
    37                  for _, q := range pq {
    38                          if refIds[q.query.RefID] {
    39                                  return ErrDuplicateRefId
    40                          }
    41                          refIds[q.query.RefID] = true
    42                  }
    43          }
    44
    45          // Skip header validation. See https://github.com/grafana/grafana/pull/58871
    46          if true {
    47                  return nil
    48          }
    49
    50          reqCtx := contexthandler.FromContext(ctx)
    51
    52          if reqCtx == nil || reqCtx.Req == nil {
    53                  return nil
    54          }
    55
    56          httpReq := reqCtx.Req
    57
    58          if pr.hasExpression {
    59                  hasExpr := httpReq.URL.Query().Get("expression")
    60                  if hasExpr == "" || hasExpr == "true" {
    61                          return nil
    62                  }
    63                  return ErrQueryParamMismatch
    64          }
    65
    66          vals := splitHeaders(httpReq.Header.Values(HeaderDatasourceUID))
    67          count := len(vals)
    68          if count > 0 { // header exists
    69                  if count != len(pr.parsedQueries) {
    70                          return ErrQueryParamMismatch
    71                  }
    72                  for _, t := range vals {
    73                          if pr.parsedQueries[t] == nil {
    74                                  return ErrQueryParamMismatch
    75                          }
    76                  }
    77          }
    78
    79          vals = splitHeaders(httpReq.Header.Values(HeaderPluginID))
    80          count = len(vals)
    81          if count > 0 { // header exists
    82                  if count != len(pr.dsTypes) {
    83                          return ErrQueryParamMismatch
    84                  }
    85                  for _, t := range vals {
    86                          if !pr.dsTypes[t] {
    87                                  return ErrQueryParamMismatch
    88                          }
    89                  }
    90          }
    91          return nil
    92  }
    93
    94  func splitHeaders(headers []string) []string {
    95          out := []string{}
    96          for _, v := range headers {
    97                  if strings.Contains(v, ",") {
    98                          for _, sub := range strings.Split(v, ",") {
    99                                  out = append(out, strings.TrimSpace(sub))
   100                          }
   101                  } else {
   102                          out = append(out, v)
   103                  }
   104          }
   105          return out
   106  }

