    59
    60  func (r *subQueryREST) Connect(ctx context.Context, name string, opts runtime.Object, responder rest.Responder) (http.Handler, error) {
    61          pluginCtx, err := r.builder.getPluginContext(ctx, name)
    62
    63          if err != nil {
    64                  if errors.Is(err, datasources.ErrDataSourceNotFound) {
    65                          return nil, r.builder.datasourceResourceInfo.NewNotFound(name)
    66                  }
    67                  return nil, err
    68          }
    69
    70          return http.HandlerFunc(func(w http.ResponseWriter, req *http.Request) {
    71                  dqr := data.QueryDataRequest{}
    72                  err := web.Bind(req, &dqr)
    73                  if err != nil {
    74                          responder.Error(err)
    75                          return
    76                  }
    77
    78                  queries, dsRef, err := data.ToDataSourceQueries(dqr)
    79                  if err != nil {
    80                          responder.Error(err)
    81                          return
    82                  }
    83                  if dsRef != nil && dsRef.UID != name {
    84                          responder.Error(fmt.Errorf("expected query body datasource and request to match"))
    85                          return
    86                  }
    87
    88                  ctx = backend.WithGrafanaConfig(ctx, pluginCtx.GrafanaConfig)
    89                  ctx = contextualMiddlewares(ctx)
    90
    91                  rsp, err := r.builder.client.QueryData(ctx, &backend.QueryDataRequest{
    92                          Queries:       queries,
    93                          PluginContext: pluginCtx,
    94                          Headers:       query_headers.ExtractKnownHeaders(req.Header),
    95                  })
    96
    97                  // all errors get converted into k8 errors when sent in responder.Error and lose important context like downstream info
    98                  var e errutil.Error
    99                  if errors.As(err, &e) && e.Source == errutil.SourceDownstream {
   100                          responder.Object(int(backend.StatusBadRequest),
   101                                  &query.QueryDataResponse{QueryDataResponse: backend.QueryDataResponse{Responses: map[string]backend.DataResponse{
   102                                          "A": {
   103                                                  Error:       errors.New(e.LogMessage),
   104                                                  ErrorSource: backend.ErrorSourceDownstream,
   105                                                  Status:      backend.StatusBadRequest,
   106                                          },
   107                                  }}},
   108                          )
   109                          return
   110                  }
   111
   112                  if err != nil {
   113                          responder.Error(err)
   114                          return
   115                  }
   116                  responder.Object(query.GetResponseCode(rsp),
   117                          &query.QueryDataResponse{QueryDataResponse: *rsp},
   118                  )
   119          }), nil
   120  }

