    66  func (r *queryConvertREST) convertQueryDataRequest(ctx context.Context, req *http.Request) (*query.QueryDataRequest, error) {
    67          dqr := data.QueryDataRequest{}
    68          err := web.Bind(req, &dqr)
    69          if err != nil {
    70                  return nil, err
    71          }
    72
    73          ds := dqr.Queries[0].Datasource
    74          pluginCtx, err := r.contextProvider.PluginContextForDataSource(ctx, &backend.DataSourceInstanceSettings{
    75                  Type:       ds.Type,
    76                  UID:        ds.UID,
