    83  // ToInlineSecureValues converts secure json into InlineSecureValues with reference names
    84  // The names are predictable and can be used while we implement dual writing for secrets
    85  func ToInlineSecureValues(dsType string, dsUID string, keys iter.Seq[string]) common.InlineSecureValues {
    86          values := make(common.InlineSecureValues)
    87          for k := range keys {
    88                  h := sha256.New()
    89                  h.Write([]byte(dsType)) // plugin id
    90                  h.Write([]byte("|"))
    91                  h.Write([]byte(dsUID)) // unique identifier
    92                  h.Write([]byte("|"))
    93                  h.Write([]byte(k)) // property name
    94                  n := hex.EncodeToString(h.Sum(nil))
    95                  values[k] = common.InlineSecureValue{
    96                          Name: "ds-" + n[0:10], // predictable name for dual writing
    97                  }
    98          }
    99          if len(values) == 0 {
   100                  return nil
   101          }
   102          return values
   103  }
