    17  const (
    18          RequestStatusOK RequestStatus = iota
    19          RequestStatusCancelled
    20          RequestStatusError
    21  )
    22
    23  func (status RequestStatus) String() string {
    24          names := [...]string{"ok", "cancelled", "error"}
    25          if status < RequestStatusOK || status > RequestStatusError {
    26                  return ""
    27          }
    28
    29          return names[status]
    30  }
    31
    32  func RequestStatusFromError(err error) RequestStatus {
    33          status := RequestStatusOK
    34          if err != nil {
    35                  status = RequestStatusError
    36                  if errors.Is(err, context.Canceled) {
    37                          status = RequestStatusCancelled
    38                  } else if s, ok := grpcstatus.FromError(err); ok && s.Code() == grpccodes.Canceled || s.Code() == grpccodes.DeadlineExceeded {
    39                          status = RequestStatusCancelled
    40                  }
    41          }
    42
    43          return status
    44  }
    45
    46  func RequestStatusFromErrorString(errString string) RequestStatus {
    47          status := RequestStatusOK
    48          if errString != "" {
    49                  status = RequestStatusError
    50                  if strings.Contains(errString, context.Canceled.Error()) || strings.Contains(errString, "code = Canceled") {
    51                          status = RequestStatusCancelled
    52                  }
    53          }
    54
    55          return status
    56  }
    57
    58  func RequestStatusFromQueryDataResponse(res *backend.QueryDataResponse, err error) RequestStatus {
    59          if err != nil {
    60                  return RequestStatusFromError(err)
    61          }
    62
    63          status := RequestStatusOK
    64
    65          if res != nil {
    66                  for _, dr := range res.Responses {
    67                          if dr.Error != nil {
    68                                  s := RequestStatusFromError(dr.Error)
    69                                  if s > status {
    70                                          status = s
    71                                  }
    72
    73                                  if status == RequestStatusError {
    74                                          break
    75                                  }
    76                          }
    77                  }
    78          }
    79
    80          return status
    81  }
