    41  func (m *LoggerMiddleware) logRequest(ctx context.Context, pCtx backend.PluginContext, fn func(ctx context.Context) (instrumentationutils.RequestStatus, error)) error {
    42          start := time.Now()
    43          timeBeforePluginRequest := log.TimeSinceStart(ctx, start)
    44
    45          ctxLogger := m.logger.FromContext(ctx)
    46          logFunc := ctxLogger.Info
    47
    48          logParams := []any{
    49                  "eventName", "grafana-data-egress",
    50                  "time_before_plugin_request", timeBeforePluginRequest,
    51                  "target", m.pluginTarget(ctx, pCtx),
    52          }
    53
    54          logFunc("Plugin Request Started", logParams...)
    55
    56          status, err := fn(ctx)
    57
    58          logParams = append(logParams, "status", status.String(), "duration", time.Since(start))
    59
    60          if err != nil {
    61                  logParams = append(logParams, "error", err)
    62          }
    63          logParams = append(logParams, "statusSource", backend.ErrorSourceFromContext(ctx))
    64
    65          if status > instrumentationutils.RequestStatusOK {
    66                  logFunc = ctxLogger.Error
    67          }
    68
    69          logFunc("Plugin Request Completed", logParams...)
    70
    71          return err
    72  }
