    74  func (m *LoggerMiddleware) QueryData(ctx context.Context, req *backend.QueryDataRequest) (*backend.QueryDataResponse, error) {
    75          if req == nil {
    76                  return m.BaseHandler.QueryData(ctx, req)
    77          }
    78
    79          var resp *backend.QueryDataResponse
    80          err := m.logRequest(ctx, req.PluginContext, func(ctx context.Context) (instrumentationutils.RequestStatus, error) {
    81                  var innerErr error
    82                  resp, innerErr = m.BaseHandler.QueryData(ctx, req)
    83
    84                  if innerErr != nil {
    85                          return instrumentationutils.RequestStatusFromError(innerErr), innerErr
    86                  }
    87
    88                  ctxLogger := m.logger.FromContext(ctx)
    89                  for refID, dr := range resp.Responses {
    90                          if dr.Error != nil {
    91                                  logParams := []any{
    92                                          "refID", refID,
    93                                          "status", int(dr.Status),
    94                                          "error", dr.Error,
    95                                          "statusSource", dr.ErrorSource.String(),
    96                                          "target", m.pluginTarget(ctx, req.PluginContext),
    97                                  }
    98                                  ctxLogger.Error("Partial data response error", logParams...)
    99                          }
   100                  }
   101
   102                  return instrumentationutils.RequestStatusFromQueryDataResponse(resp, innerErr), innerErr
   103          })
   104
   105          return resp, err
   106  }
